/// <summary>
/// Creates the view.
/// </summary>
protected boolean createViews()
{
    return this.dropView(viewName) && this.executeSqlStatementWithParameters(this.createViewSqlStmt(),SqlParams::create());
}

public static void main(Args args)
{
    var builder = DBMSQLQueryStatsViewBuilder::construct();
    builder.createSqlObjects();
}

/// <summary>
/// Returns the SQL statement to create the view.
/// </summary>
private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();

    return sqlStmt;
}

private str createSQLStatement()
{
    DictField DictFieldSQLText = new DictField(tableNum(DBMSQLQueryStats), fieldNum(DBMSQLQueryStats, SQLText));
    str sqlStmt = 'SELECT ';
    sqlStmt += '1010' + ' AS ' + asRecId + ', ';
    sqlStmt += 'qs.total_elapsed_time' + ' AS ' + asTotalElapsedTime + ', ';
    sqlStmt += 'qs.total_elapsed_time/execution_count' + ' AS ' + asAvgElapsedTime + ', ';
    sqlStmt += 'execution_count' + ' AS ' + asExecutionCount + ', ';
    sqlStmt += 'min_elapsed_time' + ' AS ' + asMinElapsedTime + ', ';
    sqlStmt += 'max_elapsed_time' + ' AS ' + asMaxElapsedTime + ', ';
    sqlStmt += 'last_elapsed_time' + ' AS ' + asLastElapsedTime + ', ';
    sqlStmt += 'qs.last_execution_time' + ' AS ' + asLastExecutionTime + ', ';
    sqlStmt += 'CONVERT([varchar](128), qs.sql_handle, 1)' + ' AS ' + asSQLHandle + ', ';
    sqlStmt += 'CONVERT([varchar](128), qs.plan_handle, 1)' + ' AS ' + asPlanHandle + ', ';
    sqlStmt += strFmt('CONVERT([NVARCHAR](%1), st.text)',DictFieldSQLText.stringLen()) + ' AS ' + asSQLText + ', ';
    sqlStmt += 'qs.statement_start_offset' + ' AS ' + asStatementStartOffset + ', ';
    sqlStmt += 'qs.statement_end_offset' + ' AS ' + asStatementEndOffset + ', ';
    sqlStmt += 'qs.plan_generation_num' + ' AS ' + asPlanGenerationNum + ', ';
    sqlStmt += 'qs.creation_time' + ' AS ' + asCreationTime + ', ';
    sqlStmt += 'qs.total_worker_time' + ' AS ' + asTotalWorkerTime + ', ';
    sqlStmt += 'qs.last_worker_time' + ' AS ' + asLastWorkerTime + ', ';
    sqlStmt += 'qs.min_worker_time' + ' AS ' + asMinWorkerTime + ', ';
    sqlStmt += 'qs.max_worker_time' + ' AS ' + asMaxWorkerTime + ', ';
    sqlStmt += 'qs.total_physical_reads' + ' AS ' + asTotalPhysicalReads + ', ';
    sqlStmt += 'qs.last_physical_reads' + ' AS ' + asLastPhysicalReads + ', ';
    sqlStmt += 'qs.min_physical_reads' + ' AS ' + asMinPhysicalReads + ', ';
    sqlStmt += 'qs.max_physical_reads' + ' AS ' + asMaxPhysicalReads + ', ';
    sqlStmt += 'qs.total_logical_writes' + ' AS ' + asTotalLogicalWrites + ', ';
    sqlStmt += 'qs.last_logical_writes' + ' AS ' + asLastLogicalWrites + ', ';
    sqlStmt += 'qs.min_logical_writes' + ' AS ' + asMinLogicalWrites + ', ';
    sqlStmt += 'qs.max_logical_writes' + ' AS ' + asMaxLogicalWrites + ', ';
    sqlStmt += 'qs.total_logical_reads' + ' AS ' + asTotalLogicalReads + ', ';
    sqlStmt += 'qs.last_logical_reads' + ' AS ' + asLastLogicalReads + ', ';
    sqlStmt += 'qs.min_logical_reads' + ' AS ' + asMinLogicalReads + ', ';
    sqlStmt += 'qs.max_logical_reads' + ' AS ' + asMaxLogicalReads + ', ';
    sqlStmt += 'qs.total_clr_time' + ' AS ' + asTotalClrTime + ', ';
    sqlStmt += 'qs.last_clr_time' + ' AS ' + asLastClrTime + ', ';
    sqlStmt += 'qs.min_clr_time' + ' AS ' + asMinClrTime + ', ';
    sqlStmt += 'qs.max_clr_time' + ' AS ' + asMaxClrTime + ', ';
    sqlStmt += 'CONVERT([varchar](20), qs.query_hash, 1)' + ' AS ' + asQueryHash + ', ';
    sqlStmt += 'CONVERT([varchar](20), qs.query_plan_hash, 1)' + ' AS ' + asQueryPlanHash + ', ';
    sqlStmt += 'qs.total_rows' + ' AS ' + asTotalRows + ', ';
    sqlStmt += 'qs.last_rows' + ' AS ' + asLastRows + ', ';
    sqlStmt += 'qs.min_rows' + ' AS ' + asMinRows + ', ';
    sqlStmt += 'qs.max_rows' + ' AS ' + asMaxRows + ', ';
    sqlStmt += 'CONVERT([varchar](130), qs.statement_sql_handle, 1)' + ' AS ' + asStatementSqlHandle + ', ';
    sqlStmt += 'qs.statement_context_id' + ' AS ' + asStatementContextId + ', ';
    sqlStmt += 'qs.total_dop' + ' AS ' + asTotalDop + ', ';
    sqlStmt += 'qs.last_dop' + ' AS ' + asLastDop + ', ';
    sqlStmt += 'qs.min_dop' + ' AS ' + asMinDop + ', ';
    sqlStmt += 'qs.max_dop' + ' AS ' + asMaxDop + ', ';
    sqlStmt += 'qs.total_grant_kb' + ' AS ' + asTotalGrantKb + ', ';
    sqlStmt += 'qs.last_grant_kb' + ' AS ' + asLastGrantKb + ', ';
    sqlStmt += 'qs.min_grant_kb' + ' AS ' + asMinGrantKb + ', ';
    sqlStmt += 'qs.max_grant_kb' + ' AS ' + asMaxGrantKb + ', ';
    sqlStmt += 'qs.total_used_grant_kb' + ' AS ' + asTotalUsedGrantKb + ', ';
    sqlStmt += 'qs.last_used_grant_kb' + ' AS ' + asLastUsedGrantKb + ', ';
    sqlStmt += 'qs.min_used_grant_kb' + ' AS ' + asMinUsedGrantKb + ', ';
    sqlStmt += 'qs.max_used_grant_kb' + ' AS ' + asMaxUsedGrantKb + ', ';
    sqlStmt += 'qs.total_ideal_grant_kb' + ' AS ' + asTotalIdealGrantKb + ', ';
    sqlStmt += 'qs.last_ideal_grant_kb' + ' AS ' + asLastIdealGrantKb + ', ';
    sqlStmt += 'qs.min_ideal_grant_kb' + ' AS ' + asMinIdealGrantKb + ', ';
    sqlStmt += 'qs.max_ideal_grant_kb' + ' AS ' + asMaxIdealGrantKb + ', ';
    sqlStmt += 'qs.total_reserved_threads' + ' AS ' + asTotalReservedThreads + ', ';
    sqlStmt += 'qs.last_reserved_threads' + ' AS ' + asLastReservedThreads + ', ';
    sqlStmt += 'qs.min_reserved_threads' + ' AS ' + asMinReservedThreads + ', ';
    sqlStmt += 'qs.max_reserved_threads' + ' AS ' + asMaxReservedThreads + ', ';
    sqlStmt += 'qs.total_used_threads' + ' AS ' + asTotalUsedThreads + ', ';
    sqlStmt += 'qs.last_used_threads' + ' AS ' + asLastUsedThreads + ', ';
    sqlStmt += 'qs.min_used_threads' + ' AS ' + asMinUsedThreads + ', ';
    sqlStmt += 'qs.max_used_threads' + ' AS ' + asMaxUsedThreads + ', ';
    sqlStmt += 'qs.total_columnstore_segment_reads' + ' AS ' + asTotalColumnstoreSegmentReads + ', ';
    sqlStmt += 'qs.last_columnstore_segment_reads' + ' AS ' + asLastColumnstoreSegmentReads + ', ';
    sqlStmt += 'qs.min_columnstore_segment_reads' + ' AS ' + asMinColumnstoreSegmentReads + ', ';
    sqlStmt += 'qs.max_columnstore_segment_reads' + ' AS ' + asMaxColumnstoreSegmentReads + ', ';
    sqlStmt += 'qs.total_columnstore_segment_skips' + ' AS ' + asTotalColumnstoreSegmentSkips + ', ';
    sqlStmt += 'qs.last_columnstore_segment_skips' + ' AS ' + asLastColumnstoreSegmentSkips + ', ';
    sqlStmt += 'qs.min_columnstore_segment_skips' + ' AS ' + asMinColumnstoreSegmentSkips + ', ';
    sqlStmt += 'qs.max_columnstore_segment_skips' + ' AS ' + asMaxColumnstoreSegmentSkips + ', ';
    sqlStmt += 'qs.total_spills' + ' AS ' + asTotalSpills + ', ';
    sqlStmt += 'qs.last_spills' + ' AS ' + asLastSpills + ', ';
    sqlStmt += 'qs.min_spills' + ' AS ' + asMinSpills + ', ';
    sqlStmt += 'qs.max_spills' + ' AS ' + asMaxSpills + ', ';
    sqlStmt += 'qs.total_worker_time/execution_count' + ' AS ' + asAvgWorkerTime + ', ';
    sqlStmt += 'qs.total_physical_reads/execution_count' + ' AS ' + asAvgPhysicalReads + ', ';
    sqlStmt += 'qs.total_logical_writes/execution_count' + ' AS ' + asAvgLogicalWrites + ', ';
    sqlStmt += 'qs.total_logical_reads/execution_count' + ' AS ' + asAvgLogicalReads + ', ';
    sqlStmt += 'qs.total_clr_time/execution_count' + ' AS ' + asAvgClrTime + ', ';
    sqlStmt += 'qs.total_rows/execution_count' + ' AS ' + asAvgRows + ', ';
    sqlStmt += 'qs.total_dop/execution_count' + ' AS ' + asAvgDop + ', ';
    sqlStmt += 'qs.total_grant_kb/execution_count' + ' AS ' + asAvgGrantKb + ', ';
    sqlStmt += 'qs.total_used_grant_kb/execution_count' + ' AS ' + asAvgUsedGrantKb + ', ';
    sqlStmt += 'qs.total_ideal_grant_kb/execution_count' + ' AS ' + asAvgIdealGrantKb + ', ';
    sqlStmt += 'qs.total_reserved_threads/execution_count' + ' AS ' + asAvgReservedThreads + ', ';
    sqlStmt += 'qs.total_used_threads/execution_count' + ' AS ' + asAvgUsedThreads + ', ';
    sqlStmt += 'qs.total_columnstore_segment_reads/execution_count' + ' AS ' + asAvgColumnstoreSegmentReads + ', ';
    sqlStmt += 'qs.total_columnstore_segment_skips/execution_count' + ' AS ' + asAvgColumnstoreSegmentSkips + ', ';
    sqlStmt += 'qs.total_spills/execution_count' + ' AS ' + asAvgSpills + ' ';
    sqlStmt += 'FROM sys.dm_exec_query_stats AS qs CROSS APPLY' + ' sys.dm_exec_sql_text(qs.sql_handle) AS st' ;
    return sqlStmt;
}

